export function runScenario(scenario: Scenario): ScenarioResult {
  const results = scenario.steps.map((step) => {
    const premium = quote(step.items, {
      yearsWithMHPCO: scenario.customer.yearsWithMHPCO,
      isFollowUp: false,
    });
    return { premium };
  });
  return { results };
}
